import React, { useEffect, useState } from "react";
import "./nhanvien.css";

function Nhanvien() {
  const [employees, setEmployees] = useState([]);
  const [newUser, setNewUser] = useState({
    name: "",
    username: "",
    password: "",
    role: "",
    phonenumber: "",
    email: "",
    address: "",
    salary: "",
    salarybonus: "",
    defaultsalary: "",
    carsoldtotal: "",
  });
  const [editUser, setEditUser] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  // Fetch nhân viên từ API
  const fetchEmployees = async () => {
    setIsLoading(true);
    try {
      const response = await fetch("http://localhost:8080/api/employees");
      const data = await response.json();
      setEmployees(data);
    } catch (err) {
      setError("Lỗi khi tải danh sách nhân viên.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchEmployees();
  }, []);

  // Xử lý thêm hoặc cập nhật nhân viên
  const handleAddOrUpdateEmployee = async (e) => {
    e.preventDefault();

    const url = editUser
      ? `http://localhost:8080/api/employees/${editUser.id}`
      : "http://localhost:8080/api/employees";
    const method = editUser ? "PUT" : "POST";

    try {
      await fetch(url, {
        method,
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(newUser),
      });
      fetchEmployees(); // Tải lại danh sách sau khi thêm/sửa
      setIsModalOpen(false); // Đóng modal
      setNewUser({
        name: "",
        username: "",
        password: "",
        role: "",
        phonenumber: "",
        email: "",
        address: "",
        salary: "",
        salarybonus: "",
        defaultsalary: "",
        carsoldtotal: "",
      });
      setEditUser(null); // Reset trạng thái chỉnh sửa
    } catch (err) {
      setError("Lỗi khi thêm/cập nhật nhân viên.");
      console.error(err);
    }
  };

  // Xử lý xóa nhân viên
  const handleDelete = async (id) => {
    try {
      await fetch(`http://localhost:8080/api/employees/${id}`, {
        method: "DELETE",
      });
      fetchEmployees(); // Tải lại danh sách sau khi xóa
    } catch (err) {
      setError("Lỗi khi xóa nhân viên.");
      console.error(err);
    }
  };

  // Hiển thị modal và thiết lập trạng thái chỉnh sửa
  const handleEdit = (user) => {
    setEditUser(user);
    setNewUser(user);
    setIsModalOpen(true);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewUser({ ...newUser, [name]: value });
  };

  if (isLoading) return <p>Đang tải dữ liệu...</p>;
  if (error) return <p>{error}</p>;

  return (
    <div className="customer-table">
      <h2>Bảng Nhân Viên</h2>
      <button onClick={() => setIsModalOpen(true)} className="add-btn">
        + Thêm nhân viên
      </button>

      {isModalOpen && (
        <form onSubmit={handleAddOrUpdateEmployee} className="modal-form">
          <h3>{editUser ? "Cập nhật nhân viên" : "Thêm nhân viên mới"}</h3>
          <div className="form-body">
            <input
              type="text"
              name="name"
              placeholder="Tên nhân viên"
              value={newUser.name}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="username"
              placeholder="Tên đăng nhập"
              value={newUser.username}
              onChange={handleInputChange}
              required
            />
            <input
              type="password"
              name="password"
              placeholder="Mật khẩu"
              value={newUser.password}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="role"
              placeholder="Chức vụ"
              value={newUser.role}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="phonenumber"
              placeholder="Số điện thoại"
              value={newUser.phonenumber}
              onChange={handleInputChange}
            />
            <input
              type="email"
              name="email"
              placeholder="Email"
              value={newUser.email}
              onChange={handleInputChange}
            />
            <input
              type="text"
              name="address"
              placeholder="Địa chỉ"
              value={newUser.address}
              onChange={handleInputChange}
            />
            <input
              type="text"
              name="salary"
              placeholder="Lương"
              value={newUser.salary}
              onChange={handleInputChange}
            />
            <input
              type="text"
              name="salarybonus"
              placeholder="Lương thưởng"
              value={newUser.salarybonus}
              onChange={handleInputChange}
            />
            <input
              type="text"
              name="defaultsalary"
              placeholder="Lương mặc định"
              value={newUser.defaultsalary}
              onChange={handleInputChange}
            />
            <input
              type="text"
              name="carsoldtotal"
              placeholder="Số xe bán được"
              value={newUser.carsoldtotal}
              onChange={handleInputChange}
            />
          </div>
          <div className="form-footer">
            <button type="submit" className="save-btn">
              {editUser ? "Cập nhật" : "Thêm"}
            </button>
            <button
              type="button"
              onClick={() => {
                setIsModalOpen(false);
                setEditUser(null);
                setNewUser({
                  name: "",
                  username: "",
                  password: "",
                  role: "",
                  phonenumber: "",
                  email: "",
                  address: "",
                  salary: "",
                  salarybonus: "",
                  defaultsalary: "",
                  carsoldtotal: "",
                });
              }}
              className="cancel-btn"
            >
              Hủy
            </button>
          </div>
        </form>
      )}

      <table>
        <thead>
          <tr>
            <th>Tên nhân viên</th>
            <th>Chức vụ</th>
            <th>SĐT</th>
            <th>Email</th>
            <th>Địa chỉ</th>
            <th>Lương</th>
            <th>Lương thưởng</th>
            <th>Lương mặc định</th>
            <th>Số xe bán được</th>
            <th>Thay đổi</th>
          </tr>
        </thead>
        <tbody>
          {employees.map((user) => (
            <tr key={user.id}>
              <td>{user.name}</td>
              <td>{user.role}</td>
              <td>{user.phonenumber}</td>
              <td>{user.email}</td>
              <td>{user.address}</td>
              <td>{user.salary}</td>
              <td>{user.salarybonus}</td>
              <td>{user.defaultsalary}</td>
              <td>{user.carsoldtotal}</td>
              <td>
                <button onClick={() => handleEdit(user)} className="edit-btn">
                  Sửa
                </button>
                <button
                  onClick={() => handleDelete(user.id)}
                  className="delete-btn"
                >
                  Xóa
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Nhanvien;
